/**
 * Integration tests for the full analytics pipeline.
 *
 * These tests exercise the complete path: HTTP-style request params →
 * route handlers → AnalyticsService → repositories → in-memory database,
 * verifying end-to-end correctness of the analytics feature.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  getDashboardHandler,
  getMetricHandler,
  getOrderAnalyticsHandler,
  getUserAnalyticsHandler,
} from '../../src/routes/analytics.routes.js';
import type { AnalyticsQueryParams } from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Test data factories
// ---------------------------------------------------------------------------

let orderSeq = 0;
let userSeq = 0;

function makeOrder(overrides: Partial<Order> = {}): Order {
  orderSeq++;
  return {
    id: `order-${orderSeq}`,
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 50 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2025-01-15T12:00:00Z'),
    updatedAt: new Date('2025-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> = {}): User {
  userSeq++;
  return {
    id: `user-${userSeq}`,
    name: `User ${userSeq}`,
    email: `user${userSeq}@example.com`,
    role: 'member',
    createdAt: new Date('2025-01-15T12:00:00Z'),
    updatedAt: new Date('2025-01-15T12:00:00Z'),
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Shared setup
// ---------------------------------------------------------------------------

describe('Analytics Pipeline Integration Tests', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    orderSeq = 0;
    userSeq = 0;
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // =========================================================================
  // 1. Dashboard end-to-end
  // =========================================================================

  describe('Dashboard — full pipeline', () => {
    it('returns complete dashboard with realistic multi-entity data', async () => {
      // Seed users
      userRepo.save(makeUser({ role: 'admin', createdAt: new Date('2025-01-05T10:00:00Z') }));
      userRepo.save(makeUser({ role: 'member', createdAt: new Date('2025-01-10T10:00:00Z') }));
      userRepo.save(makeUser({ role: 'member', createdAt: new Date('2025-01-20T10:00:00Z') }));

      // Seed orders across different dates and statuses
      orderRepo.save(makeOrder({ total: 100, status: 'delivered', createdAt: new Date('2025-01-05T14:00:00Z') }));
      orderRepo.save(makeOrder({ total: 200, status: 'pending', createdAt: new Date('2025-01-10T09:00:00Z') }));
      orderRepo.save(makeOrder({ total: 150, status: 'shipped', createdAt: new Date('2025-01-15T11:00:00Z') }));
      orderRepo.save(makeOrder({ total: 75, status: 'cancelled', createdAt: new Date('2025-01-20T16:00:00Z') }));

      const params: AnalyticsQueryParams = {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
        granularity: 'day',
      };

      const result = await getDashboardHandler(service, params);

      expect(result.success).toBe(true);
      const { data } = result;

      // Top-level shape
      expect(data.generatedAt).toBeInstanceOf(Date);
      expect(data.timeRange.start).toEqual(new Date('2025-01-01T00:00:00Z'));
      expect(data.timeRange.end).toEqual(new Date('2025-01-31T23:59:59Z'));

      // Metrics: should have all 4
      expect(data.metrics).toHaveLength(4);
      const metricTypes = data.metrics.map((m) => m.type);
      expect(metricTypes).toContain('revenue');
      expect(metricTypes).toContain('orders');
      expect(metricTypes).toContain('users');
      expect(metricTypes).toContain('average-order-value');

      // Order analytics
      expect(data.orders.totalOrders).toBe(4);
      expect(data.orders.totalRevenue).toBe(525);
      expect(data.orders.averageOrderValue).toBeCloseTo(131.25);
      expect(data.orders.statusBreakdown.delivered).toBe(1);
      expect(data.orders.statusBreakdown.pending).toBe(1);
      expect(data.orders.statusBreakdown.shipped).toBe(1);
      expect(data.orders.statusBreakdown.cancelled).toBe(1);
      expect(data.orders.statusBreakdown.confirmed).toBe(0);

      // Order time series
      expect(data.orders.revenueSeries.label).toBe('revenue');
      expect(data.orders.revenueSeries.points.length).toBeGreaterThan(0);
      expect(data.orders.orderCountSeries.label).toBe('orders');

      // User analytics
      expect(data.users.totalUsers).toBe(3);
      expect(data.users.newUsers).toBe(3);
      expect(data.users.usersByRole).toEqual({ admin: 1, member: 2 });
      expect(data.users.newUserSeries.label).toBe('newUsers');
    });

    it('correctly scopes data to the requested time range', async () => {
      // Orders: one inside range, one outside
      orderRepo.save(makeOrder({ total: 100, createdAt: new Date('2025-01-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 999, createdAt: new Date('2025-03-01T10:00:00Z') })); // outside

      // Users: one inside, one outside
      userRepo.save(makeUser({ createdAt: new Date('2025-01-10T10:00:00Z') }));
      userRepo.save(makeUser({ createdAt: new Date('2025-06-01T10:00:00Z') })); // outside

      const result = await getDashboardHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      expect(result.data.orders.totalOrders).toBe(1);
      expect(result.data.orders.totalRevenue).toBe(100);
      expect(result.data.users.newUsers).toBe(1);
      // totalUsers includes ALL users in the system, not just in-range
      expect(result.data.users.totalUsers).toBe(2);
    });

    it('returns zeroed analytics for an empty time range', async () => {
      // All data is outside the queried range
      orderRepo.save(makeOrder({ createdAt: new Date('2025-06-01T10:00:00Z') }));
      userRepo.save(makeUser({ createdAt: new Date('2025-06-01T10:00:00Z') }));

      const result = await getDashboardHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      expect(result.data.orders.totalOrders).toBe(0);
      expect(result.data.orders.totalRevenue).toBe(0);
      expect(result.data.orders.averageOrderValue).toBe(0);
      expect(result.data.users.newUsers).toBe(0);
    });
  });

  // =========================================================================
  // 2. Individual metric queries
  // =========================================================================

  describe('Metric queries — full pipeline', () => {
    beforeEach(() => {
      // Current period: Jan 1–31
      orderRepo.save(makeOrder({ total: 200, createdAt: new Date('2025-01-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 300, createdAt: new Date('2025-01-20T10:00:00Z') }));
      userRepo.save(makeUser({ createdAt: new Date('2025-01-15T10:00:00Z') }));

      // Previous period: Dec 1–31 (for period-over-period comparison)
      orderRepo.save(makeOrder({ total: 100, createdAt: new Date('2024-12-10T10:00:00Z') }));
      userRepo.save(makeUser({ createdAt: new Date('2024-12-15T10:00:00Z') }));
    });

    const params: AnalyticsQueryParams = {
      startDate: '2025-01-01T00:00:00Z',
      endDate: '2025-01-31T00:00:00Z',
      granularity: 'day',
    };

    it('revenue metric reflects order totals with period-over-period change', async () => {
      const result = await getMetricHandler(service, 'revenue', params);

      expect(result.success).toBe(true);
      expect(result.data.type).toBe('revenue');
      expect(result.data.currentValue).toBe(500); // 200 + 300
      expect(result.data.previousValue).toBe(100);
      expect(result.data.change).toBe(400); // ((500-100)/100)*100
      expect(result.data.timeSeries.label).toBe('revenue');
      expect(result.data.timeSeries.points.length).toBeGreaterThan(0);
    });

    it('orders metric reflects order count', async () => {
      const result = await getMetricHandler(service, 'orders', params);

      expect(result.success).toBe(true);
      expect(result.data.type).toBe('orders');
      expect(result.data.currentValue).toBe(2);
      expect(result.data.previousValue).toBe(1);
      expect(result.data.change).toBe(100); // ((2-1)/1)*100
    });

    it('users metric reflects new user count', async () => {
      const result = await getMetricHandler(service, 'users', params);

      expect(result.success).toBe(true);
      expect(result.data.type).toBe('users');
      expect(result.data.currentValue).toBe(1);
      expect(result.data.previousValue).toBe(1);
      expect(result.data.change).toBe(0); // no change
    });

    it('average-order-value metric is correctly computed', async () => {
      const result = await getMetricHandler(service, 'average-order-value', params);

      expect(result.success).toBe(true);
      expect(result.data.type).toBe('average-order-value');
      expect(result.data.currentValue).toBe(250); // (200+300)/2
      expect(result.data.previousValue).toBe(100); // 100/1
      expect(result.data.change).toBe(150); // ((250-100)/100)*100
    });
  });

  // =========================================================================
  // 3. Time-range filtering
  // =========================================================================

  describe('Time-range filtering', () => {
    it('hourly granularity produces correct bucketing', async () => {
      orderRepo.save(makeOrder({ total: 10, createdAt: new Date('2025-01-15T10:15:00Z') }));
      orderRepo.save(makeOrder({ total: 20, createdAt: new Date('2025-01-15T10:45:00Z') }));
      orderRepo.save(makeOrder({ total: 30, createdAt: new Date('2025-01-15T11:30:00Z') }));

      const result = await getOrderAnalyticsHandler(service, {
        startDate: '2025-01-15T10:00:00Z',
        endDate: '2025-01-15T12:00:00Z',
        granularity: 'hour',
      });

      expect(result.success).toBe(true);
      expect(result.data.totalOrders).toBe(3);
      expect(result.data.totalRevenue).toBe(60);

      // Hourly buckets should show 10+20=30 in the 10:00 bucket and 30 in the 11:00 bucket
      const revenuePoints = result.data.revenueSeries.points;
      expect(revenuePoints.length).toBeGreaterThanOrEqual(2);

      const hour10 = revenuePoints.find(
        (p) => p.timestamp.getTime() === new Date('2025-01-15T10:00:00Z').getTime(),
      );
      const hour11 = revenuePoints.find(
        (p) => p.timestamp.getTime() === new Date('2025-01-15T11:00:00Z').getTime(),
      );
      expect(hour10?.value).toBe(30); // 10 + 20
      expect(hour11?.value).toBe(30);
    });

    it('weekly granularity aggregates across days', async () => {
      // Mon Jan 6, Wed Jan 8, Mon Jan 13
      orderRepo.save(makeOrder({ total: 10, createdAt: new Date('2025-01-06T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 20, createdAt: new Date('2025-01-08T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 30, createdAt: new Date('2025-01-13T10:00:00Z') }));

      const result = await getOrderAnalyticsHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-20T00:00:00Z',
        granularity: 'week',
      });

      expect(result.success).toBe(true);
      expect(result.data.totalOrders).toBe(3);
      expect(result.data.totalRevenue).toBe(60);
      expect(result.data.revenueSeries.points.length).toBeGreaterThanOrEqual(2);
    });

    it('monthly granularity works across month boundaries', async () => {
      orderRepo.save(makeOrder({ total: 100, createdAt: new Date('2025-01-15T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 200, createdAt: new Date('2025-02-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 300, createdAt: new Date('2025-03-05T10:00:00Z') }));

      const result = await getOrderAnalyticsHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-03-31T23:59:59Z',
        granularity: 'month',
      });

      expect(result.success).toBe(true);
      expect(result.data.totalOrders).toBe(3);
      expect(result.data.totalRevenue).toBe(600);

      const points = result.data.revenueSeries.points;
      expect(points.length).toBeGreaterThanOrEqual(3);
    });

    it('narrow time range excludes data at boundaries', async () => {
      // Exactly at boundary
      orderRepo.save(makeOrder({ total: 10, createdAt: new Date('2025-01-01T00:00:00Z') }));
      // Inside range
      orderRepo.save(makeOrder({ total: 20, createdAt: new Date('2025-01-15T12:00:00Z') }));
      // At end boundary
      orderRepo.save(makeOrder({ total: 30, createdAt: new Date('2025-01-31T23:59:59Z') }));

      const result = await getOrderAnalyticsHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      // All three should be included (inclusive range)
      expect(result.data.totalOrders).toBe(3);
      expect(result.data.totalRevenue).toBe(60);
    });
  });

  // =========================================================================
  // 4. Error scenarios
  // =========================================================================

  describe('Error scenarios', () => {
    it('rejects invalid startDate across all endpoints', async () => {
      const bad: AnalyticsQueryParams = { startDate: 'not-a-date', endDate: '2025-01-31' };

      const [dashboard, metric, orders, users] = await Promise.all([
        getDashboardHandler(service, bad),
        getMetricHandler(service, 'revenue', bad),
        getOrderAnalyticsHandler(service, bad),
        getUserAnalyticsHandler(service, bad),
      ]);

      for (const r of [dashboard, metric, orders, users]) {
        expect(r.success).toBe(false);
        expect(r.error).toBe('Invalid startDate');
      }
    });

    it('rejects invalid endDate across all endpoints', async () => {
      const bad: AnalyticsQueryParams = { startDate: '2025-01-01', endDate: 'garbage' };

      const [dashboard, metric, orders, users] = await Promise.all([
        getDashboardHandler(service, bad),
        getMetricHandler(service, 'revenue', bad),
        getOrderAnalyticsHandler(service, bad),
        getUserAnalyticsHandler(service, bad),
      ]);

      for (const r of [dashboard, metric, orders, users]) {
        expect(r.success).toBe(false);
        expect(r.error).toBe('Invalid endDate');
      }
    });

    it('rejects startDate >= endDate', async () => {
      const bad: AnalyticsQueryParams = { startDate: '2025-02-01', endDate: '2025-01-01' };

      const result = await getDashboardHandler(service, bad);
      expect(result.success).toBe(false);
      expect(result.error).toBe('startDate must be before endDate');
    });

    it('rejects equal startDate and endDate', async () => {
      const bad: AnalyticsQueryParams = { startDate: '2025-01-15', endDate: '2025-01-15' };

      const result = await getDashboardHandler(service, bad);
      expect(result.success).toBe(false);
      expect(result.error).toBe('startDate must be before endDate');
    });

    it('rejects invalid granularity', async () => {
      const bad: AnalyticsQueryParams = {
        startDate: '2025-01-01',
        endDate: '2025-01-31',
        granularity: 'quarter',
      };

      const result = await getDashboardHandler(service, bad);
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid granularity');
    });

    it('rejects invalid metric type', async () => {
      const result = await getMetricHandler(service, 'conversion-rate', {
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
      expect(result.error).toContain('conversion-rate');
    });

    it('rejects empty metric type', async () => {
      const result = await getMetricHandler(service, '', {
        startDate: '2025-01-01',
        endDate: '2025-01-31',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
    });

    it('handles empty database gracefully across all endpoints', async () => {
      const params: AnalyticsQueryParams = {
        startDate: '2025-01-01',
        endDate: '2025-01-31',
        granularity: 'day',
      };

      const [dashboard, metric, orders, users] = await Promise.all([
        getDashboardHandler(service, params),
        getMetricHandler(service, 'revenue', params),
        getOrderAnalyticsHandler(service, params),
        getUserAnalyticsHandler(service, params),
      ]);

      // All should succeed with zero values
      expect(dashboard.success).toBe(true);
      expect(dashboard.data.orders.totalOrders).toBe(0);
      expect(dashboard.data.orders.totalRevenue).toBe(0);
      expect(dashboard.data.users.newUsers).toBe(0);

      expect(metric.success).toBe(true);
      expect(metric.data.currentValue).toBe(0);

      expect(orders.success).toBe(true);
      expect(orders.data.totalOrders).toBe(0);

      expect(users.success).toBe(true);
      expect(users.data.newUsers).toBe(0);
    });
  });

  // =========================================================================
  // 5. Data consistency across endpoints
  // =========================================================================

  describe('Cross-endpoint consistency', () => {
    const params: AnalyticsQueryParams = {
      startDate: '2025-01-01T00:00:00Z',
      endDate: '2025-01-31T23:59:59Z',
      granularity: 'day',
    };

    beforeEach(() => {
      orderRepo.save(makeOrder({ total: 100, status: 'delivered', createdAt: new Date('2025-01-10T10:00:00Z') }));
      orderRepo.save(makeOrder({ total: 250, status: 'pending', createdAt: new Date('2025-01-20T10:00:00Z') }));
      userRepo.save(makeUser({ role: 'admin', createdAt: new Date('2025-01-05T10:00:00Z') }));
      userRepo.save(makeUser({ role: 'member', createdAt: new Date('2025-01-25T10:00:00Z') }));
    });

    it('dashboard order data matches standalone order analytics', async () => {
      const [dashboard, orders] = await Promise.all([
        getDashboardHandler(service, params),
        getOrderAnalyticsHandler(service, params),
      ]);

      expect(dashboard.data.orders.totalOrders).toBe(orders.data.totalOrders);
      expect(dashboard.data.orders.totalRevenue).toBe(orders.data.totalRevenue);
      expect(dashboard.data.orders.averageOrderValue).toBe(orders.data.averageOrderValue);
      expect(dashboard.data.orders.statusBreakdown).toEqual(orders.data.statusBreakdown);
    });

    it('dashboard user data matches standalone user analytics', async () => {
      const [dashboard, users] = await Promise.all([
        getDashboardHandler(service, params),
        getUserAnalyticsHandler(service, params),
      ]);

      expect(dashboard.data.users.totalUsers).toBe(users.data.totalUsers);
      expect(dashboard.data.users.newUsers).toBe(users.data.newUsers);
      expect(dashboard.data.users.usersByRole).toEqual(users.data.usersByRole);
    });

    it('dashboard metrics match individual metric queries', async () => {
      const dashboard = await getDashboardHandler(service, params);

      for (const metricType of ['revenue', 'orders', 'users', 'average-order-value'] as const) {
        const metric = await getMetricHandler(service, metricType, params);
        const dashMetric = dashboard.data.metrics.find((m) => m.type === metricType);

        expect(dashMetric).toBeDefined();
        expect(dashMetric!.currentValue).toBe(metric.data.currentValue);
        expect(dashMetric!.previousValue).toBe(metric.data.previousValue);
        expect(dashMetric!.change).toBe(metric.data.change);
      }
    });
  });

  // =========================================================================
  // 6. Large dataset scenario
  // =========================================================================

  describe('Large dataset', () => {
    it('handles 100 orders and 50 users without errors', async () => {
      for (let i = 0; i < 100; i++) {
        const day = (i % 28) + 1;
        const dayStr = day.toString().padStart(2, '0');
        orderRepo.save(
          makeOrder({
            total: 10 + i,
            status: (['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'] as const)[i % 5],
            createdAt: new Date(`2025-01-${dayStr}T12:00:00Z`),
          }),
        );
      }

      for (let i = 0; i < 50; i++) {
        const day = (i % 28) + 1;
        const dayStr = day.toString().padStart(2, '0');
        userRepo.save(
          makeUser({
            role: (['admin', 'member', 'viewer'] as const)[i % 3],
            createdAt: new Date(`2025-01-${dayStr}T12:00:00Z`),
          }),
        );
      }

      const result = await getDashboardHandler(service, {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T23:59:59Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      expect(result.data.orders.totalOrders).toBe(100);
      expect(result.data.users.newUsers).toBe(50);
      expect(result.data.metrics).toHaveLength(4);

      // Status breakdown should sum to 100
      const sb = result.data.orders.statusBreakdown;
      expect(sb.pending + sb.confirmed + sb.shipped + sb.delivered + sb.cancelled).toBe(100);

      // Revenue should sum correctly
      let expectedRevenue = 0;
      for (let i = 0; i < 100; i++) expectedRevenue += 10 + i;
      expect(result.data.orders.totalRevenue).toBe(expectedRevenue);
    });
  });

  // =========================================================================
  // 7. Period-over-period with no previous data
  // =========================================================================

  describe('Period-over-period edge cases', () => {
    it('change is 0 when previous period has no data', async () => {
      // Only current period data, no previous
      orderRepo.save(makeOrder({ total: 500, createdAt: new Date('2025-01-15T10:00:00Z') }));

      const result = await getMetricHandler(service, 'revenue', {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T00:00:00Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      expect(result.data.currentValue).toBe(500);
      expect(result.data.previousValue).toBe(0);
      // When previous is 0, change should be 0 (division by zero guard)
      expect(result.data.change).toBe(0);
    });

    it('change is negative when current period is worse', async () => {
      // Previous period (Dec): more revenue
      orderRepo.save(makeOrder({ total: 1000, createdAt: new Date('2024-12-15T10:00:00Z') }));
      // Current period (Jan): less revenue
      orderRepo.save(makeOrder({ total: 200, createdAt: new Date('2025-01-15T10:00:00Z') }));

      const result = await getMetricHandler(service, 'revenue', {
        startDate: '2025-01-01T00:00:00Z',
        endDate: '2025-01-31T00:00:00Z',
        granularity: 'day',
      });

      expect(result.success).toBe(true);
      expect(result.data.currentValue).toBe(200);
      expect(result.data.previousValue).toBe(1000);
      expect(result.data.change).toBe(-80); // ((200-1000)/1000)*100
    });
  });
});

